    def get_devices_by_domain_and_obj(self, domain_code: str, obj_ids: List[str]) -> List[Dict]:
        payload = {
            "page": 1, "size": 999999, "objIds": obj_ids,
            "domainCode": domain_code, "isQueryProperties": False, "isQueryPointData": False
        }
        result = self._post('/cmdb/insRemote/getInsByDomainCodeAndObjIds', payload)
        if isinstance(result, dict):
            return result.get('data', {}).get('list', result.get('list', []))
        return result if isinstance(result, list) else []
    
    def get_point_list_by_instance(self, ins_standard_ids: List[str]) -> List[Dict]:
        result = self._post('/cmdb/insRemote/getPointDataByInsStandardIds', ins_standard_ids)
        if isinstance(result, list):
            return result
        return result.get('data', []) if isinstance(result, dict) else []
    
    def get_realtime_data(self, point_ids: List[str]) -> Dict:
        result = self._post('/device_twin/reported/list', point_ids)
        if isinstance(result, dict):
            return result.get('data', result)
        return result

# ========== ТөпҝҪпҝҪпҝҪЯјпҝҪ ==========
def main_handler(event: dict, context: dict) -> dict:
    print("=" * 60)
    print(f"[INFO] <пҝҪпҝҪДҝпҝҪпҝҪ> пҝҪпҝҪпҝҪпҝҪКј {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 60)
    
    try:
        # 1. пҝҪпҝҪИЎпҝҪиұёпҝҪРұпҝҪ
        cmdb = ZhiHangCMDB(use_internal=False)  # пҝҪпҝҪЫ·пҝҪпҝҪпҝҪпҝҪпҝҪпҝҪпҝҪпҝҪпҝҪпҝҪпҝҪ
        devices = cmdb.get_devices_by_domain_and_obj(DOMAIN_CODE, [OBJ_ID])
        print(f"[INFO] пҝҪпҝҪИЎпҝҪпҝҪ {len(devices)} пҝҪпҝҪпҝҪиұё")
        
        # 2. пҝҪпҝҪИЎпҝҪпҝҪпҝҪ
        ins_standard_ids = [d.get('insStandardId') or d.get('insId') for d in devices]
        all_points = cmdb.get_point_list_by_instance(ins_standard_ids)
        print(f"[INFO] пҝҪпҝҪИЎпҝҪпҝҪ {len(all_points)} пҝҪпҝҪпҝҪпҝҪпҝҪ")
        
        # 3. пҝҪпҝҪпҝҪпҝҪпҝҪиұёпҝҪпҝҪпҝҪУіпҝҪпҝҪ
        device_points_map = build_device_points_map(devices, all_points)
        
        # 4. пҝҪХјпҝҪпҝҪпҝҪпҝҪID
        all_phase_point_ids = []
        device_point_refs = {}
        for ins_id, points in device_points_map.items():
            for phase, point_info in points.items():
                if point_info:
                    ins_pt_id = point_info['ins_pt_id']
                    all_phase_point_ids.append(ins_pt_id)
                    device_point_refs[ins_pt_id] = (ins_id, phase)
        
        # 5. пҝҪпҝҪпҝҪпҝҪпҝҪпҝҪИЎКөКұпҝҪпҝҪпҝҪпҝҪ
        realtime_data = cmdb.get_realtime_data(all_phase_point_ids)
        if isinstance(realtime_data, dict):
            realtime_data = realtime_data.get('data', realtime_data)
        
        # 6. пҝҪпҝҪпҝҪпҝҪпҝҪиұёпҝҪпҝҪпҝҪпҝҪ
        device_current_data = {}
        for ins_pt_id, (ins_id, phase) in device_point_refs.items():
            if ins_pt_id in realtime_data:
                value = realtime_data[ins_pt_id].get('reported_value', 0)
                if ins_id not in device_current_data:
                    device_current_data[ins_id] = {}
                device_current_data[ins_id][phase] = float(value) if value else 0.0
        
        # 7. пҝҪпҝҪпҝҪпҝҪТөпҝҪпҝҪЦёпҝҪпҝҪ
        report_devices = []
        for device in devices:
            ins_id = device.get('insStandardId') or device.get('insId')
            ins_name = device.get('insName', 'Unknown')
            currents = device_current_data.get(ins_id, {})
            
            # TODO: пҝҪпҝҪпҝҪпҝҪКөпҝҪпҝҪТөпҝҪпҝҪпҝҪЯјпҝҪпҝҪпҝҪпҝҪпҝҪ
            phase_a = currents.get('a', 0)
            phase_b = currents.get('b', 0)
            phase_c = currents.get('c', 0)
            total_current = phase_a + phase_b + phase_c
            
            if total_current < MIN_CURRENT_A:
                continue
            
            # пҝҪпҝҪпҝҪпҝҪЦёпҝҪпҝҪ
            if total_current > 0:
                avg_current = total_current / 3
                max_current = max(phase_a, phase_b, phase_c)
                min_current = min(phase_a, phase_b, phase_c)
                unbalance_rate = (max_current - min_current) / avg_current * 100 if avg_current > 0 else 0
            else:
                unbalance_rate = 0
            
            report_devices.append({
                'name': ins_name,
                'phase_a': round(phase_a, 2),
                'phase_b': round(phase_b, 2),
                'phase_c': round(phase_c, 2),
                'total_current': round(total_current, 2),
                'unbalance_rate': round(unbalance_rate, 2)
            })
        
        # 8. пҝҪпҝҪпҝҪпҝҪНіпҝҪпҝҪХӘТӘ
        total_devices = len(report_devices)
        abnormal_devices = [d for d in report_devices if d['unbalance_rate'] > 15]
        avg_unbalance = sum(d['unbalance_rate'] for d in report_devices) / total_devices if total_devices > 0 else 0
        
        summary = {
            'total_devices': total_devices,
            'abnormal_count': len(abnormal_devices),
            'avg_unbalance': round(avg_unbalance, 1),
            'generated_at': datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        
        # 9. пҝҪпҝҪпҝҪпҝҪHTML
        html_content = generate_html_report(summary, report_devices)
        
        # 10. пҝҪПҙпҝҪпҝҪпҝҪMinIO
        local_html_path = '/tmp/report.html'
        with open(local_html_path, 'w', encoding='utf-8') as f:
            f.write(html_content)
        
        if MINIO_AVAILABLE:
            minio_url = upload_to_minio(local_html_path, MINIO_OBJECT_PATH)
            print(f"[INFO] MinIOпҝҪПҙпҝҪпҝҪЙ№пҝҪ: {minio_url}")
        else:
            print("[WARN] MinIO SDKпҝҪпҝҪпҝҪпҝҪпҝҪпҝҪ")
        
        return {'statusCode': 200, 'body': {'success': True, 'data': summary}}
    
    except Exception as e:
        print(f"[ERROR] пҝҪпҝҪпҝҪпҝҪК§пҝҪпҝҪ: {str(e)}\n{traceback.format_exc()}")
        return {'statusCode': 500, 'body': {'success': False, 'message': str(e)}}

# ========== пҝҪпҝҪпҝҪпҝҪпҝҪпҝҪпҝҪпҝҪ ==========
def build_device_points_map(devices: List[Dict], all_points: List[Dict]) -> Dict:
    """пҝҪпҝҪпҝҪпҝҪпҝҪиұёпҝҪпҝҪпҝҪУіпҝҪпҝҪ"""
    device_map = {}
    for device in devices:
        ins_id = device.get('insStandardId') or device.get('insId')
        device_map[ins_id] = {'a': None, 'b': None, 'c': None}
    
    for point in all_points:
        ins_standard_id = point.get('insStandardId')
        extends_name = point.get('extendsName', '')
        if not ins_standard_id:
            continue
        
        if extends_name == 'A_пҝҪпҝҪпҝҪпҝҪ_A':
            device_map[ins_standard_id]['a'] = {
                'ins_pt_id': point.get('insPointStandardId'),
                'obj_pt_id': point.get('objPointDataId')
            }
        elif extends_name == 'B_пҝҪпҝҪпҝҪпҝҪ_A':
            device_map[ins_standard_id]['b'] = {
                'ins_pt_id': point.get('insPointStandardId'),
                'obj_pt_id': point.get('objPointDataId')
            }
        elif extends_name == 'C_пҝҪпҝҪпҝҪпҝҪ_A':
            device_map[ins_standard_id]['c'] = {
                'ins_pt_id': point.get('insPointStandardId'),
                'obj_pt_id': point.get('objPointDataId')
            }
    return device_map

def generate_html_report(summary: Dict, devices: List[Dict]) -> str:
    """пҝҪпҝҪпҝҪпҝҪHTMLпҝҪпҝҪпҝҪпҝҪ - пҝҪпҝҪпҝҪпҝҪКөпҝҪпҝҪТіпҝҪпҝҪДЈпҝҪпҝҪпҝҪпҝҪРҙ"""
    # TODO: пҝҪпҝҪпҝҪпҝҪКөпҝҪпҝҪТіпҝҪпҝҪДЈпҝҪпҝҪпҝҪРҙ
    now = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    return f"<!DOCTYPE html><html><body><h1>Report generated at {now}</h1></body></html>"

def upload_to_minio(local_path: str, object_path: str) -> str:
    """пҝҪПҙпҝҪпҝҪпҝҪMinIO"""
    client = Minio(
        MINIO_ENDPOINT,
        access_key=MINIO_ACCESS_KEY,
        secret_key=MINIO_SECRET_KEY,
        secure=False
    )
    client.fput_object(MINIO_BUCKET, object_path, local_path)
    return f"http://{minio.split(':')[0]}/minio/{object_path}"
