"""
HTMLз»“жһ„и§ЈжһҗеҷЁ
жҸҗеҸ–йқҷжҖҒHTMLйЎөйқўзҡ„з»“жһ„гҖҒж ·ејҸгҖҒж•°жҚ®еҢәеҹҹе’ҢдәӨдә’е…ғзҙ 
"""

import re
import json
from bs4 import BeautifulSoup
from typing import Dict, List, Any, Optional


class HTMLParser:
    """и§ЈжһҗйқҷжҖҒHTMLжҠҘиЎЁйЎөйқўпјҢжҸҗеҸ–е…ій”®дҝЎжҒҜ"""

    def __init__(self, html_content: str):
        self.soup = BeautifulSoup(html_content, 'html.parser')
        self.html_content = html_content

    def parse(self) -> Dict[str, Any]:
        """е®Ңж•ҙи§ЈжһҗHTMLпјҢиҝ”еӣһз»“жһ„еҢ–дҝЎжҒҜ"""
        return {
            'title': self._extract_title(),
            'style': self._extract_style(),
            'scripts': self._extract_scripts(),
            'data_regions': self._extract_data_regions(),
            'interactions': self._extract_interactions(),
            'raw_html': self.html_content,
        }

    def _extract_title(self) -> str:
        """жҸҗеҸ–йЎөйқўж Үйўҳ"""
        title_tag = self.soup.find('title')
        if title_tag:
            return title_tag.get_text(strip=True)
        h1 = self.soup.find('h1')
        if h1:
            return h1.get_text(strip=True)
