        for script in script_tags:
            content = script.get_text()

            # жҹҘжүҫ const/var е®ҡд№үзҡ„ж•°жҚ®ж•°з»„
            patterns = [
                r'const\s+(\w+Data)\s*=\s*(\[.*?\]);',
                r'var\s+(\w+Data)\s*=\s*(\[.*?\]);',
