        for inp in inputs:
            placeholder = inp.get('placeholder', '')
            if placeholder:
                interactions.append({
                    'type': 'search',
                    'placeholder': placeholder
                })

        return interactions

    def _extract_icon(self, element) -> str:
        """жҸҗеҸ–еӣҫж ҮemojiжҲ–class"""
        # жҹҘжүҫemoji
        text = element.get_text()
