    def _get_style_value(self, style_str: str, property_name: str) -> Optional[str]:
        """д»Һstyleеӯ—з¬ҰдёІдёӯжҸҗеҸ–еұһжҖ§еҖј"""
        pattern = rf'{property_name}\s*:\s*([^;]+)'
