    def _extract_api_info(self) -> Dict[str, Any]:
        """жҸҗеҸ–APIз«ҜзӮ№е’Ңи®ӨиҜҒдҝЎжҒҜ"""
        api_info = {
            'type': 'unknown',
            'base_url': '',
            'auth': {}
        }

        # жҹҘжүҫжҷәиҲӘCMDB
        if 'zhihang' in self.py_content.lower() or 'cmdb' in self.py_content.lower():
            api_info['type'] = 'zhihang-cmdb'

            # жҸҗеҸ–base URL
            url_patterns = [
                r"base_url\s*=\s*['\"]([^'\"]+)['\"]",
                r"INTERNAL_BASE_URL\s*=\s*['\"]([^'\"]+)['\"]",
