import json
from typing import Dict, List, Any, Optional
from jinja2 import Environment, FileSystemLoader


class Transformer:
    """HTMLйқҷжҖҒйЎөйқў вҶ’ еҠЁжҖҒжңҚеҠЎ иҪ¬еҢ–еј•ж“Һ"""

    def __init__(self, template_dir: str = None):
        if template_dir is None:
            template_dir = os.path.join(os.path.dirname(__file__), '..', 'templates', 'service_template')

        self.env = Environment(
            loader=FileSystemLoader(template_dir),
            trim_blocks=True,
            lstrip_blocks=True
        )
        self.template_dir = template_dir

    def transform(self, html_info: Dict[str, Any], skill_info: Dict[str, Any], 
                  service_config: Dict[str, Any] = None) -> Dict[str, str]:
        """
        жү§иЎҢиҪ¬еҢ–пјҢз”ҹжҲҗе®Ңж•ҙзҡ„еҠЁжҖҒжңҚеҠЎд»Јз Ғ

        Args:
            html_info: HTMLParser.parse() зҡ„иҫ“еҮә
            skill_info: SkillParser.parse() зҡ„иҫ“еҮә
            service_config: жңҚеҠЎй…ҚзҪ®пјҲеҗҚз§°гҖҒеҲ·ж–°зӯ–з•Ҙзӯүпјү

        Returns:
            з”ҹжҲҗзҡ„ж–Үд»¶еҶ…е®№еӯ—е…ё
        """
        if service_config is None:
            service_config = {}

        # 1. жҷәиғҪеҢ№й…ҚпјҡHTMLж•°жҚ®еҢәеҹҹ вҶ” жҠҖиғҪеҢ…ж•°жҚ®иҫ“еҮә
        mapping = self._match_html_to_skill(html_info, skill_info)

        # 2. з”ҹжҲҗж•°жҚ®жӢүеҸ–жЁЎеқ—
        data_fetcher = self._generate_data_fetcher(skill_info)

        # 3. з”ҹжҲҗи®Ўз®—жЁЎеқ—
        calculator = self._generate_calculator(skill_info)

        # 4. з”ҹжҲҗеҠЁжҖҒHTMLпјҲе°ҶйқҷжҖҒж•°жҚ®жӣҝжҚўдёәжЁЎжқҝеҸҳйҮҸпјү
        dynamic_html = self._generate_dynamic_html(html_info, mapping)

        # 5. з”ҹжҲҗFlaskдё»еә”з”Ё
        flask_app = self._generate_flask_app(html_info, skill_info, mapping, service_config)

        # 6. з”ҹжҲҗDockerй…ҚзҪ®
        dockerfile = self._generate_dockerfile()
        docker_compose = self._generate_docker_compose(service_config)

        # 7. з”ҹжҲҗrequirements.txt
        requirements = self._generate_requirements(skill_info)

        # 8. з”ҹжҲҗжңҚеҠЎй…ҚзҪ®
        config_yaml = self._generate_service_config(service_config, skill_info)

        return {
            'app.py': flask_app,
            'data_fetcher.py': data_fetcher,
            'calculator.py': calculator,
            'templates/index.html': dynamic_html,
            'Dockerfile': dockerfile,
            'docker-compose.yml': docker_compose,
            'requirements.txt': requirements,
            'config.yml': config_yaml,
            '_mapping.json': json.dumps(mapping, ensure_ascii=False, indent=2),
        }

    def _match_html_to_skill(self, html_info: Dict[str, Any], skill_info: Dict[str, Any]) -> Dict[str, Any]:
        """жҷәиғҪеҢ№й…ҚHTMLж•°жҚ®еҢәеҹҹдёҺжҠҖиғҪеҢ…ж•°жҚ®иҫ“еҮә"""
        mapping = {
            'stat_cards': {},
            'tables': {},
            'conclusions': {},
            'refresh_strategy': 'cron'
        }

        # еҢ№й…Қз»ҹи®ЎеҚЎзүҮ
        for region in html_info.get('data_regions', []):
            if region['type'] == 'stat_cards':
                for card in region.get('items', []):
                    data_key = card.get('data_key', '')
                    label = card.get('label', '')

                    # ж №жҚ®ж ҮзӯҫжҺЁж–ӯеҜ№еә”зҡ„ж•°жҚ®жәҗ
                    if 'и®ҫеӨҮ' in label or 'еҸ°' in label or 'count' in data_key:
                        mapping['stat_cards'][data_key] = {
                            'source': 'len(results)',
                            'label': label,
                            'type': 'count'
                        }
                    elif 'е№іеқҮ' in label or 'avg' in data_key:
                        mapping['stat_cards'][data_key] = {
                            'source': 'avg_unbalance',
                            'label': label,
                            'type': 'average'
                        }
                    elif 'жңҖеӨ§' in label or 'max' in data_key:
                        mapping['stat_cards'][data_key] = {
                            'source': 'max_unbalance',
                            'label': label,
                            'type': 'maximum'
                        }
                    elif 'ејӮеёё' in label or 'abnormal' in data_key:
                        mapping['stat_cards'][data_key] = {
                            'source': 'abnormal_count',
                            'label': label,
                            'type': 'count'
                        }

            elif region['type'] == 'data_table':
                mapping['tables']['main'] = {
                    'columns': region.get('columns', []),
                    'data_source': 'abnormal_data',
                    'sort_by': 'unbalance DESC'
                }

            elif region['type'] == 'conclusion_box':
                mapping['conclusions'] = {
                    'items': region.get('items', []),
                    'data_source': 'summary_stats'
                }

        # д»ҺжҠҖиғҪеҢ…жҺЁж–ӯеҲ·ж–°зӯ–з•Ҙ
        calc = skill_info.get('calculation', {})
        if calc.get('thresholds', {}).get('abnormal'):
            mapping['thresholds'] = calc['thresholds']

        return mapping

    def _generate_data_fetcher(self, skill_info: Dict[str, Any]) -> str:
        """з”ҹжҲҗж•°жҚ®жӢүеҸ–жЁЎеқ—"""
        template = self.env.get_template('data_fetcher.py.j2')

        context = {
            'data_source': skill_info.get('data_source', {}),
            'fetch_steps': skill_info.get('fetch_steps', []),
            'config': skill_info.get('config', {}),
        }

        return template.render(**context)

    def _generate_calculator(self, skill_info: Dict[str, Any]) -> str:
        """з”ҹжҲҗи®Ўз®—жЁЎеқ—"""
        template = self.env.get_template('calculator.py.j2')

        calc = skill_info.get('calculation', {})
        config = skill_info.get('config', {})

        context = {
            'formula': calc.get('formula', ''),
            'formula_description': calc.get('formula_description', ''),
            'filters': calc.get('filters', []),
            'thresholds': calc.get('thresholds', {}),
            'point_mapping': config.get('point_mapping', {}),
        }

        return template.render(**context)

    def _generate_dynamic_html(self, html_info: Dict[str, Any], mapping: Dict[str, Any]) -> str:
        """е°ҶйқҷжҖҒHTMLиҪ¬еҢ–дёәеҠЁжҖҒжЁЎжқҝ"""
        raw_html = html_info.get('raw_html', '')

        # 1. е°ҶзЎ¬зј–з Ғж•°жҚ®жӣҝжҚўдёәJinja2жЁЎжқҝеҸҳйҮҸ
        # з»ҹи®ЎеҚЎзүҮж•°еҖј
        for key, info in mapping.get('stat_cards', {}).items():
            # жҹҘжүҫе№¶жӣҝжҚўеҜ№еә”зҡ„ж•°еҖј
            value_pattern = rf'(<[^>]*class="[^"]*stat-value[^"]*"[^>]*>)([^<]+)(</[^>]*>)'
            # иҝҷйҮҢз®ҖеҢ–еӨ„зҗҶпјҢе®һйҷ…еә”иҜҘжӣҙзІҫзЎ®еҢ№й…Қ

        # 2. е°ҶеҶ…еөҢж•°жҚ®ж•°з»„жӣҝжҚўдёәжЁЎжқҝеҸҳйҮҸ
        raw_html = re.sub(
            r'const\s+\w+Data\s*=\s*\[.*?\];',
            'const abnormalData = {{ data_json|safe }};',
            raw_html,
            flags=re.DOTALL
        )

        # 3. ж·»еҠ еҠЁжҖҒеҲ·ж–°и„ҡжң¬
        refresh_script = self._generate_refresh_script(mapping)

        # 4. еңЁ</body>еүҚжҸ’е…ҘеҲ·ж–°и„ҡжң¬
        if '</body>' in raw_html:
            raw_html = raw_html.replace('</body>', refresh_script + '\n</body>')

        # 5. е°ҶйқҷжҖҒз»ҹи®ЎеҖјжӣҝжҚўдёәжЁЎжқҝеҸҳйҮҸ
        # жңүж•Ҳи®ҫеӨҮж•°
        raw_html = self._replace_stat_value(raw_html, r'жңүж•Ҳи®ҫеӨҮ', '{{ summary.valid_count }}')
        raw_html = self._replace_stat_value(raw_html, r'е№іеқҮдёҚе№іиЎЎеәҰ', '{{ summary.avg_unbalance }}%')
        raw_html = self._replace_stat_value(raw_html, r'жңҖеӨ§дёҚе№іиЎЎеәҰ', '{{ summary.max_unbalance }}%')
        raw_html = self._replace_stat_value(raw_html, r'ејӮеёёи®ҫеӨҮ', '{{ summary.abnormal_count }}')

        # 6. жӣҝжҚўеҲ·ж–°ж—¶й—ҙ
        raw_html = raw_html.replace(
            'id="refreshTime">--',
            'id="refreshTime">{{ refresh_time }}'
        )

        # 7. жӣҝжҚўз»“и®әеҢәеҹҹ
        raw_html = self._replace_conclusions(raw_html, mapping)

        return raw_html

    def _replace_stat_value(self, html: str, label_pattern: str, template_var: str) -> str:
        """жӣҝжҚўз»ҹи®ЎеҚЎзүҮзҡ„ж•°еҖј"""
        # жҹҘжүҫеҢ…еҗ«зү№е®ҡж Үзӯҫзҡ„з»ҹи®ЎеҚЎзүҮпјҢжӣҝжҚўе…¶дёӯзҡ„ж•°еҖј
        pattern = rf'(<[^>]*>[^<]*{label_pattern}[^<]*</[^>]*>\s*</div>\s*<div[^>]*class="[^"]*(?:stat-value|text-3xl)[^"]*"[^>]*>)([^<]+)(</div>)'

        def replacer(match):
            return match.group(1) + template_var + match.group(3)

