def upload_html():
    """дёҠдј HTMLж–Үд»¶"""
    if 'file' not in request.files:
        return jsonify({'success': False, 'message': 'жІЎжңүж–Үд»¶'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'success': False, 'message': 'ж–Үд»¶еҗҚдёәз©ә'}), 400

    if not allowed_file(file.filename, ALLOWED_HTML_EXTENSIONS):
        return jsonify({'success': False, 'message': 'еҸӘе…Ғи®ёдёҠдј HTMLж–Үд»¶'}), 400

    try:
        # з”ҹжҲҗе”ҜдёҖID
