        filename = f"{upload_id}_{secure_filename(file.filename)}"
        filepath = os.path.join(UPLOAD_FOLDER, filename)

        file.save(filepath)

        # иҜ»еҸ–еҶ…е®№
        with open(filepath, 'r', encoding='utf-8') as f:
            content = f.read()

        return jsonify({
            'success': True,
