                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9"/>
                            </svg>
                        </div>
                        <div>
                            <div class="text-sm text-gray-400">дё–зәӘдә’иҒ”</div>
                            <div class="text-lg font-semibold text-white">21Vianet</div>
                        </div>
                    </div>

                    <div class="h-10 w-px bg-gray-700"></div>

                    <div class="flex items-center gap-3">
                        <div class="w-10 h-10 rounded-lg bg-gradient-to-br from-purple-500 to-pink-600 flex items-center justify-center">
                            <svg class="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z"/>
                            </svg>
                        </div>
                        <div>
                            <div class="text-sm text-gray-400">ж•°жҚ®дёӯеҝғиҝҗз»ҙ</div>
                            <div class="text-lg font-semibold text-white">DC Operations</div>
                        </div>
                    </div>
                </div>

                <div class="flex items-center gap-4">
                    <div class="text-right">
                        <div class="text-sm text-gray-400">ж•°жҚ®еҲ·ж–°ж—¶й—ҙ</div>
                        <div class="text-cyan-400 font-mono" id="refreshTime">{{ refresh_time }}</div>
                    </div>
                    <button onclick="refreshData()" id="refreshBtn" class="refresh-btn flex items-center gap-2 px-4 py-2 rounded-lg text-white font-medium cursor-pointer">
                        <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/>
                        </svg>
                        еҲ·ж–°ж•°жҚ®
                    </button>
                    <button onclick="exportToExcel()" id="exportBtn" class="export-btn flex items-center gap-2 px-4 py-2 rounded-lg text-white font-medium cursor-pointer">
                        <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/>
                        </svg>
                        еҜјеҮәExcel
                    </button>
                </div>
            </div>
        </div>
    </header>

    <main class="max-w-7xl mx-auto px-6 py-8">
        <div class="text-center mb-8">
            <h1 class="text-3xl font-bold text-white mb-2">рҹ”Ң {{ title }}</h1>
            <p class="text-gray-400">{{ datacenter }} В· е®һж—¶зӣ‘жөӢ В· еҠЁжҖҒеҲ·ж–°</p>
            <div class="mt-2 inline-flex items-center gap-2 px-3 py-1 rounded-full bg-gray-800 text-xs text-gray-400">
                <span class="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                иҮӘеҠЁеҲ·ж–°дёӯ
            </div>
        </div>

        <!-- ж ёеҝғз»“и®ә -->
        <div class="conclusion-box rounded-xl p-6 mb-8">
            <h3 class="text-lg font-semibold text-purple-400 mb-4 flex items-center gap-2">
                <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/>
                </svg>
                ж ёеҝғз»“и®ә
            </h3>
            <div class="grid md:grid-cols-3 gap-6" id="conclusionBox">
                <div class="flex items-start gap-3">
                    <span class="text-2xl">рҹҡЁ</span>
                    <div>
                        <div class="text-red-400 font-semibold">зҙ§жҖҘеӨ„зҗҶ ({{ summary.urgent_count or 0 }}еҸ°)</div>
                        <div class="text-sm text-gray-300 mt-1">дёҚе№іиЎЎеәҰвүҘ40%и®ҫеӨҮеӯҳеңЁдёҘйҮҚиҙҹиҪҪдёҚеқҮ<br>йңҖз«ӢеҚіе®үжҺ’жЈҖдҝ®</div>
                    </div>
                </div>
                <div class="flex items-start gap-3">
                    <span class="text-2xl">вҡ пёҸ</span>
                    <div>
                        <div class="text-orange-400 font-semibold">йҮҚзӮ№е…іжіЁ ({{ summary.focus_count or 0 }}еҸ°)</div>
                        <div class="text-sm text-gray-300 mt-1">дёҚе№іиЎЎеәҰ>15%и®ҫеӨҮ<br>е»әи®®дјҳеҢ–иҙҹиҪҪеҲҶй…Қ</div>
                    </div>
                </div>
                <div class="flex items-start gap-3">
                    <span class="text-2xl">рҹ“Ҡ</span>
                    <div>
                        <div class="text-cyan-400 font-semibold">ж•ҙдҪ“иҜ„дј° ({{ summary.valid_count or 0 }}еҸ°)</div>
                        <div class="text-sm text-gray-300 mt-1">е№іеқҮдёҚе№іиЎЎеәҰ{{ summary.avg_unbalance or 0 }}%<br>ејӮеёёзҺҮ{{ summary.abnormal_pct or 0 }}%пјҢйңҖжҢҒз»ӯзӣ‘жҺ§</div>
                    </div>
                </div>
            </div>
        </div>

        <!-- з»ҹи®ЎеҚЎзүҮ -->
        <div class="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8" id="statCards">
            <div class="glass-card p-5 text-center">
                <div class="text-sm text-gray-400 mb-2">жңүж•Ҳи®ҫеӨҮ</div>
                <div class="text-3xl font-bold stat-value" id="statValidCount">{{ summary.valid_count or 0 }}</div>
                <div class="text-xs text-gray-500 mt-1">еҸ°</div>
            </div>
            <div class="glass-card p-5 text-center">
                <div class="text-sm text-gray-400 mb-2">е№іеқҮдёҚе№іиЎЎеәҰ</div>
                <div class="text-3xl font-bold stat-value" id="statAvgUnbalance">{{ summary.avg_unbalance or 0 }}%</div>
                <div class="text-xs text-gray-500 mt-1">жӯЈеёёйҳҲеҖј15%</div>
            </div>
            <div class="glass-card p-5 text-center">
                <div class="text-sm text-gray-400 mb-2">жңҖеӨ§дёҚе№іиЎЎеәҰ</div>
                <div class="text-3xl font-bold text-red-400" id="statMaxUnbalance">{{ summary.max_unbalance or 0 }}%</div>
                <div class="text-xs text-gray-500 mt-1">{{ summary.max_device or '' }}</div>
            </div>
            <div class="glass-card p-5 text-center">
                <div class="text-sm text-gray-400 mb-2">ејӮеёёи®ҫеӨҮ</div>
                <div class="text-3xl font-bold text-orange-400" id="statAbnormalCount">{{ summary.abnormal_count or 0 }}</div>
                <div class="text-xs text-gray-500 mt-1">еҚ жҜ” {{ summary.abnormal_pct or 0 }}%</div>
            </div>
        </div>

        <!-- ж•°жҚ®иЎЁж ј -->
        <div class="glass-card overflow-hidden">
            <div class="px-6 py-4 border-b border-gray-700 flex items-center justify-between">
                <h2 class="text-lg font-semibold text-white flex items-center gap-2">
                    <svg class="w-5 h-5 text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"/>
                    </svg>
                    ејӮеёёи®ҫеӨҮжё…еҚ• (дёҚе№іиЎЎеәҰ > 15%)
                </h2>
                <span class="text-xs text-gray-500 bg-gray-800 px-3 py-1 rounded-full" id="tableCount">е…ұ {{ devices|length }} еҸ°</span>
            </div>

            <div class="overflow-x-auto">
                <table class="data-table">
                    <thead>
                        <tr>
                            <th class="w-16">жҺ’еҗҚ</th>
                            <th>и®ҫеӨҮеҗҚз§°</th>
                            <th>жҘјеұӮ</th>
                            <th class="text-right">Aзӣё(A)</th>
                            <th class="text-right">Bзӣё(A)</th>
                            <th class="text-right">Cзӣё(A)</th>
                            <th class="text-right">жҖ»з”өжөҒ(A)</th>
                            <th class="text-right">дёҚе№іиЎЎеәҰ</th>
                        </tr>
                    </thead>
                    <tbody id="abnormalTable">
                        {% for item in devices %}
                        <tr>
                            <td>
                                <span class="rank-badge {% if item.rank == 1 %}rank-1{% elif item.rank == 2 %}rank-2{% elif item.rank == 3 %}rank-3{% else %}rank-other{% endif %}">
                                    {{ item.rank }}
                                </span>
                            </td>
                            <td class="font-medium text-white">{{ item.insName }}</td>
                            <td><span class="floor-tag floor-{{ item.floor|lower }}">{{ item.floor }}</span></td>
                            <td class="text-right text-cyan-300">{{ item.A }}</td>
                            <td class="text-right text-cyan-300">{{ item.B }}</td>
                            <td class="text-right text-cyan-300">{{ item.C }}</td>
                            <td class="text-right font-mono">{{ item.total }}</td>
                            <td class="text-right">
                                <span class="unbalance-tag 
                                    {% if item.unbalance >= 40 %}unbalance-critical
                                    {% elif item.unbalance >= 30 %}unbalance-high
                                    {% elif item.unbalance >= 20 %}unbalance-medium
                                    {% else %}unbalance-normal{% endif %}">
                                    {{ item.unbalance }}%
                                </span>
                            </td>
                        </tr>
                        {% endfor %}
                    </tbody>
                </table>
            </div>
        </div>

        <div class="text-center mt-8 text-gray-500 text-sm">
            <p>дё–зәӘдә’иҒ” В· DCиҝҗз»ҙжҷәиғҪзӣ‘жҺ§е№іеҸ° В· ж•°жҚ®жқҘжәҗпјҡжҷәиҲӘCMDB В· еҠЁжҖҒеҲ·ж–°</p>
        </div>
    </main>

    <!-- ToastйҖҡзҹҘ -->
    <div id="toast" class="toast"></div>

    <script>
        // еҪ“еүҚж•°жҚ®
        let abnormalData = {{ devices|tojson|safe }};
        let summaryData = {{ summary|tojson|safe }};

        // иҮӘеҠЁеҲ·ж–°й—ҙйҡ”пјҲ5еҲҶй’ҹпјү
        const REFRESH_INTERVAL = 300000;
        let refreshTimer = null;

        // жҳҫзӨәToast
        function showToast(message, type = 'info') {
            const toast = document.getElementById('toast');
            toast.textContent = message;
            toast.className = `toast ${type}`;
            toast.classList.add('show');
            setTimeout(() => toast.classList.remove('show'), 3000);
        }

        // еҲ·ж–°ж•°жҚ®
        async function refreshData() {
            const btn = document.getElementById('refreshBtn');
            btn.classList.add('spinning');
            btn.disabled = true;

            try {
                const response = await fetch('./api/data');
                const result = await response.json();

                if (result.success) {
                    abnormalData = result.devices;
                    summaryData = result.summary;

                    // жӣҙж–°з»ҹи®ЎеҚЎзүҮ
                    updateStatCards(summaryData);

                    // жӣҙж–°иЎЁж ј
                    updateTable(abnormalData);

                    // жӣҙж–°еҲ·ж–°ж—¶й—ҙ
                    document.getElementById('refreshTime').textContent = result.refresh_time;

                    showToast('ж•°жҚ®еҲ·ж–°жҲҗеҠҹ', 'success');
                } else {
                    showToast(result.message || 'еҲ·ж–°еӨұиҙҘ', 'error');
                }
            } catch (error) {
                console.error('еҲ·ж–°еӨұиҙҘ:', error);
                showToast('еҲ·ж–°еӨұиҙҘ: ' + error.message, 'error');
            } finally {
                btn.classList.remove('spinning');
                btn.disabled = false;
            }
        }

        // жӣҙж–°з»ҹи®ЎеҚЎзүҮ
        function updateStatCards(summary) {
            document.getElementById('statValidCount').textContent = summary.valid_count || 0;
            document.getElementById('statAvgUnbalance').textContent = (summary.avg_unbalance || 0) + '%';
            document.getElementById('statMaxUnbalance').textContent = (summary.max_unbalance || 0) + '%';
            document.getElementById('statAbnormalCount').textContent = summary.abnormal_count || 0;
            document.getElementById('tableCount').textContent = `е…ұ ${abnormalData.length} еҸ°`;

            // жӣҙж–°з»“и®ә
            updateConclusions(summary);
        }

        // жӣҙж–°з»“и®ә
        function updateConclusions(summary) {
            const box = document.getElementById('conclusionBox');
            box.innerHTML = `
                <div class="flex items-start gap-3">
                    <span class="text-2xl">рҹҡЁ</span>
                    <div>
                        <div class="text-red-400 font-semibold">зҙ§жҖҘеӨ„зҗҶ (${summary.urgent_count || 0}еҸ°)</div>
                        <div class="text-sm text-gray-300 mt-1">дёҚе№іиЎЎеәҰвүҘ40%и®ҫеӨҮеӯҳеңЁдёҘйҮҚиҙҹиҪҪдёҚеқҮ<br>йңҖз«ӢеҚіе®үжҺ’жЈҖдҝ®</div>
                    </div>
                </div>
                <div class="flex items-start gap-3">
                    <span class="text-2xl">вҡ пёҸ</span>
                    <div>
                        <div class="text-orange-400 font-semibold">йҮҚзӮ№е…іжіЁ (${summary.focus_count || 0}еҸ°)</div>
                        <div class="text-sm text-gray-300 mt-1">дёҚе№іиЎЎеәҰ>15%и®ҫеӨҮ<br>е»әи®®дјҳеҢ–иҙҹиҪҪеҲҶй…Қ</div>
                    </div>
                </div>
                <div class="flex items-start gap-3">
                    <span class="text-2xl">рҹ“Ҡ</span>
                    <div>
                        <div class="text-cyan-400 font-semibold">ж•ҙдҪ“иҜ„дј° (${summary.valid_count || 0}еҸ°)</div>
                        <div class="text-sm text-gray-300 mt-1">е№іеқҮдёҚе№іиЎЎеәҰ${summary.avg_unbalance || 0}%<br>ејӮеёёзҺҮ${summary.abnormal_pct || 0}%пјҢйңҖжҢҒз»ӯзӣ‘жҺ§</div>
                    </div>
                </div>
            `;
        }

        // иҺ·еҸ–жҘјеұӮж ·ејҸ
        function getFloorClass(floor) {
            const floorMap = {
                'F1': 'floor-f1', 'F2': 'floor-f2', 'F3': 'floor-f3',
                'F4': 'floor-f4', 'F5': 'floor-f5', 'F6': 'floor-f6', 'F7': 'floor-f7'
            };
            return floorMap[floor] || 'floor-f1';
        }

        // иҺ·еҸ–дёҚе№іиЎЎеәҰж ·ејҸ
        function getUnbalanceClass(unbalance) {
            if (unbalance >= 40) return 'unbalance-critical';
            if (unbalance >= 30) return 'unbalance-high';
            if (unbalance >= 20) return 'unbalance-medium';
            return 'unbalance-normal';
        }

        // иҺ·еҸ–жҺ’еҗҚж ·ејҸ
        function getRankClass(rank) {
            if (rank === 1) return 'rank-1';
            if (rank === 2) return 'rank-2';
            if (rank === 3) return 'rank-3';
            return 'rank-other';
        }

        // жӣҙж–°иЎЁж ј
        function updateTable(devices) {
            const tbody = document.getElementById('abnormalTable');
            tbody.innerHTML = devices.map(item => `
                <tr>
                    <td><span class="rank-badge ${getRankClass(item.rank)}">${item.rank}</span></td>
                    <td class="font-medium text-white">${item.insName}</td>
                    <td><span class="floor-tag ${getFloorClass(item.floor)}">${item.floor}</span></td>
                    <td class="text-right text-cyan-300">${item.A}</td>
                    <td class="text-right text-cyan-300">${item.B}</td>
                    <td class="text-right text-cyan-300">${item.C}</td>
                    <td class="text-right font-mono">${item.total}</td>
                    <td class="text-right"><span class="unbalance-tag ${getUnbalanceClass(item.unbalance)}">${item.unbalance}%</span></td>
                </tr>
            `).join('');
        }

        // еҜјеҮәExcel
        function exportToExcel() {
            const btn = document.getElementById('exportBtn');
            const originalContent = btn.innerHTML;
            btn.innerHTML = '<svg class="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg> еҜјеҮәдёӯ...';
            btn.disabled = true;

            try {
                const wb = XLSX.utils.book_new();

                const wsData = [
                    ['еәҸеҸ·', 'и®ҫеӨҮеҗҚз§°', 'жҘјеұӮ', 'Aзӣёз”өжөҒ(A)', 'Bзӣёз”өжөҒ(A)', 'Cзӣёз”өжөҒ(A)', 'жҖ»з”өжөҒ(A)', 'дёҚе№іиЎЎеәҰ(%)', 'йЈҺйҷ©зӯүзә§']
                ];

                abnormalData.forEach(item => {
                    let risk = 'дҪҺ';
                    if (item.unbalance >= 40) risk = 'зҙ§жҖҘ';
                    else if (item.unbalance >= 30) risk = 'й«ҳ';
                    else if (item.unbalance >= 20) risk = 'дёӯ';

                    wsData.push([
                        item.rank, item.insName, item.floor,
                        item.A, item.B, item.C, item.total,
                        item.unbalance, risk
                    ]);
                });

                const ws = XLSX.utils.aoa_to_sheet(wsData);
                ws['!cols'] = [
                    {wch: 6}, {wch: 28}, {wch: 8}, {wch: 14},
                    {wch: 14}, {wch: 14}, {wch: 12}, {wch: 14}, {wch: 10}
                ];

                XLSX.utils.book_append_sheet(wb, ws, 'дёҚе№іиЎЎеәҰејӮеёёи®ҫеӨҮ');

                const fileName = `{{ title }}_ејӮеёёи®ҫеӨҮжё…еҚ•_${new Date().toISOString().slice(0,10)}.xlsx`;
                XLSX.writeFile(wb, fileName);

                btn.innerHTML = '<svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7"/></svg> еҜјеҮәжҲҗеҠҹ!';
                showToast('ExcelеҜјеҮәжҲҗеҠҹ', 'success');

                setTimeout(() => {
                    btn.innerHTML = originalContent;
                    btn.disabled = false;
                }, 2000);

            } catch (error) {
                console.error('еҜјеҮәеӨұиҙҘ:', error);
                showToast('еҜјеҮәеӨұиҙҘ: ' + error.message, 'error');
                btn.innerHTML = originalContent;
                btn.disabled = false;
            }
        }

        // еҗҜеҠЁиҮӘеҠЁеҲ·ж–°
        function startAutoRefresh() {
            refreshTimer = setInterval(refreshData, REFRESH_INTERVAL);
        }

        // йЎөйқўеҸҜи§ҒжҖ§еҸҳеҢ–ж—¶еӨ„зҗҶ
        document.addEventListener('visibilitychange', () => {
            if (document.visibilityState === 'visible') {
                refreshData();
                if (!refreshTimer) startAutoRefresh();
            } else {
                if (refreshTimer) {
                    clearInterval(refreshTimer);
                    refreshTimer = null;
                }
            }
        });

        // еҲқе§ӢеҢ–
        startAutoRefresh();
    </script>
</body>
</html>
"}

